        assert_eq!(strip_code_fence("```\n[1,2]\n```"), "[1,2]");
        assert_eq!(strip_code_fence("{\"x\":1}"), "{\"x\":1}"); // no fence → unchanged
        assert_eq!(strip_code_fence("  {\"x\":1}  "), "{\"x\":1}"); // trimmed
