    #[test]
    fn parse_tolerates_idle_pane_with_empty_or_unknown_wave() {
        // auto-role/right-size: the weak ORCH_MODEL emits idle panes as {task:"", wave:""}.
        // serde validates EVERY array element BEFORE the empty-task filter runs, so a lenient
        // Wave (#[serde(other)] → Code) is what keeps one idle pane's empty wave from failing
        // the whole parse. The idle pane is then dropped; the real task survives. (Caught by
        // the empirical haiku union test — the redesign's own wave deserialize was fragile here.)
        let env = envelope(
            "{\"two_wave\":false,\"tasks\":[\
              {\"id\":\"a\",\"role\":\"builder\",\"task\":\"do x\",\"wave\":\"code\"},\
              {\"id\":\"b\",\"role\":\"scout\",\"task\":\"\",\"wave\":\"\"}]}",
        );
        let o = parse_orchestration(&env, &known(&["a", "b"])).unwrap();
        assert_eq!(o.tasks.len(), 1, "idle pane (empty task) dropped, real task kept");
        assert_eq!(o.tasks[0].id, "a");
        assert_eq!(o.tasks[0].wave, Wave::Code);
        // a present-but-garbage wave on a REAL task → Code (safe default), never an Err.
        let env2 = envelope("[{\"id\":\"a\",\"task\":\"y\",\"wave\":\"banana\"}]");
        let o2 = parse_orchestration(&env2, &known(&["a"])).unwrap();
        assert_eq!(o2.tasks[0].wave, Wave::Code, "unknown wave string → Code, not Err");
    }

