    #[test]
    fn resolve_external_ws_prefix_match_wins_over_tag() {
        let live = vec!["ws44255x3-p0".to_string(), "ws44255x3-p1".to_string()];
        // A live ws-prefix target resolves WITHOUT consulting the registry…
        assert_eq!(resolve_external_ws("ws44255x3", &live, None).as_deref(), Some("ws44255x3"));
        // …and beats a registry tag of the same name pointing elsewhere.
        let reg = lreg(vec![lw("ws9x1-p0", Some("ws44255x3"))]);
        assert_eq!(
            resolve_external_ws("ws44255x3", &live, Some(&reg)).as_deref(),
            Some("ws44255x3")
        );
        // A prefix that matches no live id is NOT a match ("ws4" ≠ "ws44255x3").
        assert_eq!(resolve_external_ws("ws4", &live, None), None);
    }

    #[test]
    fn resolve_external_ws_unique_tag_resolves_ambiguous_declines() {
        let reg = lreg(vec![
            lw("ws1x1-p0", Some("alpha")),
            lw("ws1x1-p1", Some("alpha")), // same ws twice → still ONE distinct prefix
            lw("ws2x1-p0", Some("beta")),
            lw("ws3x1-p0", Some("beta")), // beta spans TWO workspaces → ambiguous
        ]);
        assert_eq!(resolve_external_ws("alpha", &[], Some(&reg)).as_deref(), Some("ws1x1"));
        // Ambiguous tag DECLINES (mirrors the FE resolveExternalTarget) — never picks one.
        assert_eq!(resolve_external_ws("beta", &[], Some(&reg)), None);
        // Unknown target / no registry → None (the FE keeps its own check).
        assert_eq!(resolve_external_ws("gamma", &[], Some(&reg)), None);
        assert_eq!(resolve_external_ws("alpha", &[], None), None);
    }

    #[test]
    fn add_pane_ceiling_check_refuses_at_and_above_the_cap() {
        assert!(add_pane_ceiling_check(7, 8, "ws1x1").is_ok());
        assert!(add_pane_ceiling_check(0, 1, "ws1x1").is_ok());
        // AT the cap refuses (adding one more would exceed it), naming count + cap + knob.
        let e = add_pane_ceiling_check(8, 8, "ws1x1").unwrap_err();
        assert_eq!(e.0, response_code::BAD_REQUEST);
        assert!(e.1.contains("(8/8)") && e.1.contains("external_spawn_max_panes"), "{}", e.1);
        assert!(add_pane_ceiling_check(16, 16, "ws1x1").is_err());
    }

    #[test]
    fn external_orchestrator_op_subset_excludes_delegate_and_lifecycle() {
        use agent_teams_core::op_external_orchestrator_allowed as ext_ok;
        // visible-pane control IS allowed
        assert!(ext_ok(&SocketRequest::SendInput { id: "w".into(), text: "y".into() }));
        assert!(ext_ok(&SocketRequest::Broadcast { text: "y".into() }));
        assert!(ext_ok(&SocketRequest::Orchestrate { goal: "g".into(), dispatch: false, target_workspace: None }));
        assert!(ext_ok(&SocketRequest::Focus { id: "w".into() }));
        // autonomous / lifecycle / multi-hop stay coordinator-only (NOT external)
        assert!(!ext_ok(&SocketRequest::Delegate {
            parent_id: "p".into(),
            goal: "g".into(),
            max_workers: 1,
            depth: 1,
        }));
        assert!(!ext_ok(&SocketRequest::Synthesize { dir: "d".into(), goal: "g".into() }));
        assert!(!ext_ok(&SocketRequest::Handoff {
            from: "a".into(),
            to: "b".into(),
            instruction: "i".into(),
        }));
        assert!(!ext_ok(&SocketRequest::ListLive));
    }

    #[test]
    fn delegate_precheck_enforces_every_gate_in_order() {
        use agent_teams_core::response_code;
        // autonomy ceiling L0 (default) ⇒ refuse FIRST, before any other check.
        assert_eq!(
            delegate_precheck(0, 1, "ship it", true).unwrap_err().0,
            response_code::AUTONOMY_DISABLED
        );
        // ceiling ok, but depth>1 ⇒ DEPTH_EXCEEDED (the recursion/cycle guard, pre-spawn).
        assert_eq!(
            delegate_precheck(1, 2, "ship it", true).unwrap_err().0,
            response_code::DEPTH_EXCEEDED
        );
        // ceiling + depth ok, but empty/whitespace goal ⇒ BAD_REQUEST.
        assert_eq!(
            delegate_precheck(1, 1, "   ", true).unwrap_err().0,
            response_code::BAD_REQUEST
        );
        // everything ok but parent isn't a live pane ⇒ UNKNOWN_WORKSPACE.
        assert_eq!(
            delegate_precheck(1, 1, "ship it", false).unwrap_err().0,
            response_code::UNKNOWN_WORKSPACE
        );
        // all gates satisfied ⇒ proceed to admission.
        assert!(delegate_precheck(1, 1, "ship it", true).is_ok());
        // a higher ceiling still passes (MVP only distinguishes 0 vs >=1).
        assert!(delegate_precheck(3, 1, "ship it", true).is_ok());
    }

    #[test]
    fn delegate_wrap_task_carries_run_dir_filename_and_sentinel() {
        // The dispatch-critical invariant: a worker's prompt MUST name its exact report
        // path + the `## BOUNDARIES` completion sentinel, or bridge_ready never marks it
        // complete and the settle loop times out every run. One line (\n-submits-TUI).
        let w = delegate_wrap_task("do the thing", "/repo/bridge/delegate-1", "delegate-1-w0", false);
        assert!(
            w.contains("/repo/bridge/delegate-1/delegate-1-w0.md"),
            "must name the EXACT report path the worker writes"
        );
        assert!(
            w.contains("## BOUNDARIES"),
            "must include the completion sentinel bridge_ready polls for"
        );
        assert!(w.starts_with("do the thing"), "must preserve the orchestrated task verbatim");
        assert!(!w.contains('\n'), "must stay ONE line (the \\n-submits-TUI invariant)");
        // report-only (write_mode=false) carries NO commit instruction.
        assert!(!w.contains("git commit"), "report-only wrap must not instruct a commit");
    }

    // Phase 2 write-mode wrap: the worker must be told to COMMIT, and — load-bearing (advisor) —
    // the commit instruction must come BEFORE the report-write so the `## BOUNDARIES` settle
    // sentinel implies the commit already landed (else the fold races ahead + drops the fix).
    #[test]
    fn delegate_wrap_task_write_mode_commits_before_writing_the_report() {
        let w = delegate_wrap_task("fix the bug", "/repo/bridge/fw-1", "fw-1-w0", true);
        assert!(w.contains("git add -A && git commit"), "write-mode must instruct a commit");
        assert!(w.contains("## BOUNDARIES"), "still carries the completion sentinel");
        // ORDERING: the commit instruction precedes the report-path instruction → BOUNDARIES last.
        let commit_at = w.find("git commit").expect("commit present");
        let report_at = w.find("write your COMPLETE result").expect("report instruction present");
        assert!(commit_at < report_at, "commit MUST be instructed before the report-write (settle-implies-committed)");
        assert!(!w.contains('\n'), "must stay ONE line");
    }

    /// The pre-library `delegate_wrap_task` write protocol, spelled INDEPENDENTLY (one
    /// string per source piece — never derived from the roles consts under test). This is
    /// the near-inert landing lock for the section-library refactor (ADE slice 2): the
    /// extracted wording must survive byte-identically inside the new composition.
    fn pre_library_delegate_report(run_dir: &str, id: &str, when: &str) -> String {
        let mut s = String::new();
        s += "  —  When finished";
        s += when;
        s += ", write your COMPLETE result as Markdown to this EXACT path";
        s += " (create parent dirs; overwrite; use EXACTLY this filename, invent no other): ";
        s += run_dir;
        s += "/";
        s += id;
        s += ".md . It MUST contain these H2 sections IN ORDER —";
        s += " \"## BASE\": paste verbatim `git rev-parse HEAD`, `git rev-parse main`, `git merge-base HEAD main`;";
        s += " \"## CHANGED\": first run `git merge-base HEAD main` to get the BASE sha, then paste `git diff --stat <that-base-sha>` (do NOT use a $(...) subshell) and `git status --short`;";
        s += " \"## VERIFIED\": for each check, the exact command and its verbatim tail output (never a result you did not run);";
        s += " \"## CONTRACT\": every public symbol/command/event/type signature other panes depend on, exact, one per line;";
        s += " \"## UNVERIFIED\": every claim you could NOT check and why;";
        s += " \"## BOUNDARIES\": the files you touched. An empty section is its heading plus \"none\".";
        s
    }

    #[test]
    fn delegate_wrap_task_keeps_the_pre_library_write_protocol_byte_identical() {
        // Report-only: the old literal rides VERBATIM inside the new composition (the
        // defense/freshness/escalation preamble is inserted BEFORE it; the LESSON hook
        // after) and the whole wrap is exactly task + the library's section block.
        let w = delegate_wrap_task("do the thing", "/repo/bridge/delegate-1", "delegate-1-w0", false);
        let old = pre_library_delegate_report("/repo/bridge/delegate-1", "delegate-1-w0", "");
        assert!(
            w.contains(&old),
            "the pre-library write protocol must survive byte-identically inside the wrap"
        );
        assert_eq!(
            w,
            format!(
                "do the thing{}",
                roles::dispatch_sections(
                    roles::PromptRole::Verifier,
                    "/repo/bridge/delegate-1",
                    "delegate-1-w0",
                    ""
                )
            ),
            "the wrap is exactly task + the library section block (no site-local prose left)"
        );
        assert!(
            w.contains(roles::LESSON_HOOK),
            "the LESSON harvest hook must reach every delegate worker"
        );
        // Write-mode: the when-note still rides inside "When finished{note}," and the old
        // protocol (with the note) is still byte-identical.
        let wm = delegate_wrap_task("fix the bug", "/repo/bridge/fw-1", "fw-1-w0", true);
        let old_wm = pre_library_delegate_report(
            "/repo/bridge/fw-1",
            "fw-1-w0",
            " (do this LAST, AFTER you have committed)",
        );
        assert!(wm.contains(&old_wm), "write-mode protocol must stay byte-identical too");
    }

    #[test]
    fn role_prompt_sections_projection_matches_the_library_composition() {
        // The JS splice contract: preamble + report_head + "<runDir>/<paneId>.md" +
        // report_tail must equal the Rust-side dispatch_sections byte-for-byte, for BOTH
        // roles — so the GUI Bridge and the delegate path can never drift apart.
        for (wire, role) in [
            ("worker", roles::PromptRole::Worker),
            ("verifier", roles::PromptRole::Verifier),
        ] {
            let p = role_prompt_sections(wire.to_string()).expect("known role");
            assert_eq!(
                format!("{}{}{}/{}.md{}", p.preamble, p.report_head, "/runs/b1", "ws1-p0", p.report_tail),
                roles::dispatch_sections(role, "/runs/b1", "ws1-p0", ""),
                "{wire}: the JS splice must reproduce the Rust composition"
            );
            for (name, text) in [
                ("preamble", &p.preamble),
                ("report_head", &p.report_head),
                ("report_tail", &p.report_tail),
            ] {
                assert!(!text.contains('\n'), "{wire}/{name} must be single-line");
            }
        }
        // Unknown role is a hard Err (a protocol-less dispatch would silently never settle).
        assert!(role_prompt_sections("coordinator".to_string()).is_err());
        assert!(role_prompt_sections("".to_string()).is_err());
    }

    #[test]
    fn orchestrate_dispatch_line_stays_normalizable_with_sections_on() {
        // The exact composition socket_orchestrate now sends (prime "" when the gate is
        // off): task + the flattened section block. It must still pass the Model-A
        // single-line gate, keep the pre-library report line byte-identical, and carry
        // the LESSON hook.
        let task = "fix the wipe";
        let line = format!("{}{}", task, roles::orchestrate_sections("/tmp/at-run", "ws1-p0"));
        assert!(
            normalize_input(&line).is_ok(),
            "sections must never make a sendable orchestrate task unsendable"
        );
        let mut old = String::new();
        old += " — When finished, write your COMPLETE report as Markdown to this EXACT absolute path: ";
        old += "/tmp/at-run/ws1-p0.md";
        old += " (create parent dirs; overwrite if it exists). The LAST line of the file MUST be exactly \"## BOUNDARIES\".";
        assert!(
            line.contains(&old),
            "the pre-library socket report line must survive byte-identically"
        );
        assert!(line.starts_with(task), "task text stays first (after any prime)");
        assert!(line.contains(roles::LESSON_HOOK), "LESSON hook reaches the socket path");
    }

    // The token/cost meter parsers: a json envelope + a stream-json worker log share the usage
    // shape; missing fields read as zeros (never error — the meter must not fail a run); `add`
    // accumulates the orchestrator + workers + synthesizer into one run total.
    #[test]
    fn claude_usage_parses_both_shapes_and_sums() {
        // --output-format json envelope: nested usage + top-level total_cost_usd.
        let env = serde_json::json!({
            "result": "doc",
            "usage": { "input_tokens": 100, "output_tokens": 20, "cache_read_input_tokens": 5000, "cache_creation_input_tokens": 300 },
            "total_cost_usd": 0.42
        });
        let a = ClaudeUsage::from_value(&env);
        assert_eq!((a.input, a.output, a.cache_read, a.cache_creation), (100, 20, 5000, 300));
        assert!((a.cost_usd - 0.42).abs() < 1e-9);

        // absent usage/cost → all zeros, no panic.
        let empty = ClaudeUsage::from_value(&serde_json::json!({ "result": "x" }));
        assert_eq!(empty, ClaudeUsage::default());

        // stream-json log: the LAST {"type":"result",…} line wins; non-result lines ignored.
        let dir = std::env::temp_dir().join(format!("fw-usage-{}", std::process::id()));
        std::fs::create_dir_all(&dir).unwrap();
        let log = dir.join("w.log");
        std::fs::write(
            &log,
            "{\"type\":\"assistant\"}\n{\"type\":\"result\",\"usage\":{\"input_tokens\":7,\"output_tokens\":3},\"total_cost_usd\":0.01}\n",
        )
        .unwrap();
        let b = ClaudeUsage::from_stream_log(&log);
        assert_eq!((b.input, b.output), (7, 3));
        assert!((b.cost_usd - 0.01).abs() < 1e-9);
        // missing log file → zeros (a worker whose usage was never reported costs 0, honestly).
        assert_eq!(ClaudeUsage::from_stream_log(&dir.join("nope.log")), ClaudeUsage::default());

        // add() accumulates a run total (orchestrator + worker here).
        let mut total = a;
        total.add(&b);
        assert_eq!((total.input, total.output), (107, 23));
        assert!((total.cost_usd - 0.43).abs() < 1e-9);
    }

    // The run-history audit log: NEWEST-first, malformed lines skipped, partial lines tolerated
    // (serde(default)). This is what lets old runs/reports/PRs survive an app restart.
    #[test]
    fn parse_run_history_newest_first_and_tolerant() {
        let body = "{\"run_id\":\"delegate-1\",\"verdict\":\"pass\"}\n\
                    not json — skip me\n\
                    {\"run_id\":\"delegate-2\",\"verdict\":\"hold\",\"pr_url\":\"http://x/1\"}\n";
        let h = parse_run_history(body);
        assert_eq!(h.len(), 2, "two valid lines; the garbage line is skipped");
        assert_eq!(h[0].run_id, "delegate-2", "newest (last-appended) first");
        assert_eq!(h[1].run_id, "delegate-1");
        // partial line tolerated via serde(default): missing fields are empty, not an error.
        assert_eq!(h[1].verdict, "pass");
        assert_eq!(h[1].pr_url, None);
        assert_eq!(h[1].usage, ClaudeUsage::default());
        // empty log → empty history, never panics.
        assert!(parse_run_history("").is_empty());
        // missing `initiator` defaults to human → kept (back-compat for pre-v2 records).
        assert_eq!(h[0].initiator, "human");
    }

    // v2 History contract: the view shows HUMAN-initiated runs only — an autonomous agent's
    // self-delegation (initiator:"agent") is filtered out, and workspace_id round-trips for scoping.
    #[test]
    fn parse_run_history_drops_agent_initiated_and_keeps_workspace_id() {
        let body = "{\"run_id\":\"d-h\",\"initiator\":\"human\",\"workspace_id\":\"ws-1\"}\n\
                    {\"run_id\":\"d-a\",\"initiator\":\"agent\",\"workspace_id\":\"ws-1\"}\n\
                    {\"run_id\":\"d-old\"}\n";
        let h = parse_run_history(body);
        let ids: Vec<&str> = h.iter().map(|r| r.run_id.as_str()).collect();
        assert!(ids.contains(&"d-h"), "human-initiated kept");
        assert!(ids.contains(&"d-old"), "pre-v2 (no initiator → human) kept");
        assert!(!ids.contains(&"d-a"), "agent self-delegation filtered OUT of human History");
        let hrec = h.iter().find(|r| r.run_id == "d-h").unwrap();
        assert_eq!(hrec.workspace_id, "ws-1", "workspace_id round-trips for scoping");
    }

    // P2 cap fix: the auto-default scales with cores but FLOORS at the old default (3) and
    // HARD-CAPS at 8 — the autonomy bound never silently widens past the ceiling.
    #[test]
    fn clamp_default_cap_floors_at_three_and_ceils_at_sixteen() {
        assert_eq!(clamp_default_cap(0), 3, "0 cores → floor 3 (never below the old default)");
        assert_eq!(clamp_default_cap(1), 3, "1 core → sub-one underflows → floor 3");
        assert_eq!(clamp_default_cap(4), 3, "4 cores → 3 (leave one for the UI)");
        assert_eq!(clamp_default_cap(5), 4, "5 cores → 4");
        assert_eq!(clamp_default_cap(9), 8, "9 cores → 8 (one less than cores)");
        assert_eq!(clamp_default_cap(12), 11, "12 cores → 11 → budget cap-1=10 → 10 delegate workers reachable");
        assert_eq!(clamp_default_cap(17), 16, "17 cores → 16 (hits the ceiling)");
        assert_eq!(clamp_default_cap(33), 16, "32+ cores → still 16 (hard ceiling, raised 8→16)");
    }

    // P2 cap fix: occupancy frees a slot ONLY for a settled idle/done pane; everything else
    // (state-blind harness absent from the queue, working, waiting, fresh-spawn) stays
    // occupied → the budget can never oversubscribe the hard cap.
    #[test]
    fn occupied_slots_frees_only_settled_idle_panes() {
        use std::collections::HashSet;
        let live: HashSet<String> =
            ["a", "b", "c", "d"].iter().map(|s| s.to_string()).collect();
        let row = |id: &str, st: &str| QueueRow {
            id: id.into(),
            harness: "claude".into(),
            state: st.into(),
            reason: None,
            needs_human: false,
            since: 0,
            role: None,
            tag: None,
            workspace: None,
        };
        // a=idle(free) b=done(free) c=working(occupied) d=absent/state-blind(occupied) → 2 occupied
        let q = vec![row("a", "idle"), row("b", "done"), row("c", "working")];
        assert_eq!(occupied_slots(&live, &q), 2);
        // empty queue = every pane state-blind/fresh → all 4 occupied (the conservative floor)
        assert_eq!(occupied_slots(&live, &[]), 4);
        // waiting (needs human) counts as occupied — it will resume; only b(idle) is free → 3 occupied
        let q2 = vec![row("a", "waiting"), row("b", "idle")];
        assert_eq!(occupied_slots(&live, &q2), 3);
    }

