    #[test]
    fn response_codes_round_trip_through_the_shared_contract() {
        // The app emits these exact strings; the sidecar maps them. Lock the wire.
        let r = SocketResponse::err(response_code::DEAD_PANE, "dead");
        let s = serde_json::to_string(&r).unwrap();
        let back: SocketResponse = serde_json::from_str(&s).unwrap();
        assert_eq!(back, r);
        assert_eq!(back.code, "DEAD_PANE");
        assert!(!back.ok);
        // a request the sidecar would send parses on the app side
        let req: SocketRequest =
            serde_json::from_str(r#"{"op":"send_input","id":"w1","text":"y"}"#).unwrap();
        assert_eq!(req, SocketRequest::SendInput { id: "w1".into(), text: "y".into() });
    }

    // ───────────────── 06-03 Context Router (app-side helpers) ──────────────────

    #[test]
    fn dispatch_plan_preview_dispatches_nothing_dispatch_writes_all() {
        // D23 fail-safe: dispatch:false (preview) ⇒ ZERO writes, regardless of how
        // many tasks the synthesizer produced — the host inspects, then confirms.
        let mapping = vec![
            Dispatch { id: "a".into(), task: "do A".into(), wave: Wave::Code, ..Default::default() },
            Dispatch { id: "b".into(), task: "do B".into(), wave: Wave::Code, ..Default::default() },
        ];
        assert!(
            dispatch_plan(false, &mapping).is_empty(),
            "preview must dispatch nothing"
        );
        // dispatch:true ⇒ every row is a write target.
        assert_eq!(dispatch_plan(true, &mapping).len(), 2);
        // An empty mapping is trivially empty either way (never panics).
        assert!(dispatch_plan(true, &[]).is_empty());
    }

    #[test]
    fn dispatch_partitions_normalize_failures_into_dropped() {
        // A synthesized task with an interior newline fails normalize_input; it must
        // be ACCOUNTED FOR (the caller folds `dropped` into `skipped`), never silently
        // lost. Every input id ends up in targets ∪ dropped.
        let mapping = [
            Dispatch { id: "ok".into(), task: "do A".into(), wave: Wave::Code, ..Default::default() },
            Dispatch { id: "bad".into(), task: "do X\nthen Y".into(), wave: Wave::Code, ..Default::default() },
        ];
        let (targets, dropped) = partition_normalizable(&mapping);
        assert_eq!(targets.len(), 1, "the clean task is a write target");
        assert_eq!(targets[0].0, "ok");
        assert_eq!(dropped, vec!["bad".to_string()], "the newline task is reported, not dropped");
        // accountability invariant: no dispatched id silently vanishes.
        assert_eq!(targets.len() + dropped.len(), mapping.len());
    }

